BASE = Path(r"C:\Users\MSI\Desktop\kik_proje")
PY = BASE / ".py"
PKG = PY / "204"

def write(name, text):
    p = PKG / name
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(text, encoding="utf-8")

CONFIG = '# -*- coding: utf-8 -*-\nfrom pathlib import Path\n\nBASE_DIR = Path(r"C:\\Users\\MSI\\Desktop\\kik_proje")\nPY_DIR = BASE_DIR / ".py"\nSTATE_DIR = BASE_DIR / "production_state"\nREPORT_DIR = BASE_DIR / "raporlar"\n\nMETRICS_DIR = STATE_DIR / "metrics"\nMETRICS_STORE = METRICS_DIR / "204_metrics_snapshot.json"\nMETRICS_HISTORY = METRICS_DIR / "204_metrics_history.jsonl"\n\nQUEUE_FILE = STATE_DIR / "job_queue" / "198_job_queue_state.json"\nWORKER_FILE = STATE_DIR / "job_queue" / "198_worker_state.json"\nEVENT_LOG = STATE_DIR / "event_bus" / "201_event_bus.jsonl"\nPLATFORM_LOG = STATE_DIR / "logs" / "203_platform.log.jsonl"\n\nMIN_DISK_GB = 50\n'

UTILS = '# -*- coding: utf-8 -*-\nimport json\nimport shutil\nfrom pathlib import Path\nfrom datetime import datetime\n\ndef now_stamp():\n    return datetime.now().strftime("%Y%m%d_%H%M%S")\n\ndef now_text():\n    return datetime.now().strftime("%Y-%m-%d %H:%M:%S")\n\ndef ensure_dirs(*dirs):\n    for d in dirs:\n        Path(d).mkdir(parents=True, exist_ok=True)\n\ndef disk_free_gb(path):\n    usage = shutil.disk_usage(str(path))\n    return round(usage.free / (1024 ** 3), 2)\n\ndef safe_read(path, limit_chars=2000000):\n    path = Path(path)\n    if not path.exists():\n        return ""\n    for enc in ("utf-8", "utf-8-sig", "cp1254", "latin-1"):\n        try:\n            return path.read_text(encoding=enc, errors="ignore")[:limit_chars]\n        except Exception:\n            pass\n    return ""\n\ndef safe_json(path):\n    path = Path(path)\n    if not path.exists():\n        return None\n    try:\n        return json.loads(safe_read(path))\n    except Exception:\n        return None\n\ndef write_json(path, data):\n    path = Path(path)\n    path.parent.mkdir(parents=True, exist_ok=True)\n    path.write_text(json.dumps(data, ensure_ascii=False, indent=2), encoding="utf-8")\n\ndef append_jsonl(path, data):\n    path = Path(path)\n    path.parent.mkdir(parents=True, exist_ok=True)\n    with path.open("a", encoding="utf-8") as f:\n        f.write(json.dumps(data, ensure_ascii=False) + "\\n")\n\ndef latest_file(folder, pattern):\n    folder = Path(folder)\n    if not folder.exists():\n        return None\n    files = list(folder.glob(pattern))\n    if not files:\n        return None\n    files.sort(key=lambda p: p.stat().st_mtime, reverse=True)\n    return files[0]\n'

COLLECTOR = '# -*- coding: utf-8 -*-\nimport json\nimport sqlite3\nfrom pathlib import Path\nfrom config import BASE_DIR, STATE_DIR, QUEUE_FILE, WORKER_FILE, EVENT_LOG, PLATFORM_LOG\nfrom utils import safe_json, safe_read, disk_free_gb, latest_file\n\ndef collect_db_metrics():\n    candidates = [p for p in BASE_DIR.rglob("*.db") if "kik" in p.name.lower()]\n    candidates = list(set(candidates))\n    candidates.sort(key=lambda p: p.stat().st_mtime, reverse=True)\n    if not candidates:\n        return {"status": "FAIL", "count": 0, "path": None, "message": "DB bulunamadı."}\n    db_path = candidates[0]\n    try:\n        conn = sqlite3.connect(str(db_path))\n        cur = conn.cursor()\n        tables = [x[0] for x in cur.execute("SELECT name FROM sqlite_master WHERE type=\'table\'").fetchall()]\n        table = "hukuki_kartlar" if "hukuki_kartlar" in tables else (tables[0] if tables else None)\n        if not table:\n            conn.close()\n            return {"status": "FAIL", "count": 0, "path": str(db_path), "message": "Tablo yok."}\n        count = cur.execute(f"SELECT COUNT(*) FROM {table}").fetchone()[0]\n        conn.close()\n        return {"status": "PASS", "count": count, "path": str(db_path), "table": table, "message": f"DB OK: {count}"}\n    except Exception as e:\n        return {"status": "FAIL", "count": 0, "path": str(db_path), "message": str(e)}\n\ndef collect_queue_metrics():\n    q = safe_json(QUEUE_FILE)\n    if not q:\n        return {"status": "WARNING", "total": 0, "message": "Queue yok veya okunamadı."}\n    jobs = q.get("jobs", [])\n    counts = {}\n    for j in jobs:\n        st = j.get("status", "UNKNOWN")\n        counts[st] = counts.get(st, 0) + 1\n    total = len(jobs)\n    finished = counts.get("FINISHED", 0)\n    failed = counts.get("FAILED", 0)\n    completion_rate = round((finished / total) * 100, 2) if total else 0\n    return {\n        "status": "PASS" if failed == 0 else "WARNING",\n        "total": total,\n        "waiting": counts.get("WAITING", 0),\n        "running": counts.get("RUNNING", 0),\n        "finished": finished,\n        "failed": failed,\n        "retry": counts.get("RETRY", 0),\n        "completion_rate": completion_rate,\n        "message": f"Queue total={total}, finished={finished}, failed={failed}"\n    }\n\ndef collect_worker_metrics():\n    w = safe_json(WORKER_FILE)\n    if not w:\n        return {"status": "WARNING", "total": 0, "message": "Worker state yok veya okunamadı."}\n    workers = w.get("workers", [])\n    counts = {}\n    completed = 0\n    failed = 0\n    for worker in workers:\n        st = worker.get("status", "UNKNOWN")\n        counts[st] = counts.get(st, 0) + 1\n        completed += int(worker.get("jobs_completed", 0) or 0)\n        failed += int(worker.get("jobs_failed", 0) or 0)\n    return {\n        "status": "PASS",\n        "total": len(workers),\n        "idle": counts.get("IDLE", 0),\n        "running": counts.get("RUNNING", 0),\n        "disabled": counts.get("DISABLED", 0),\n        "jobs_completed": completed,\n        "jobs_failed": failed,\n        "message": f"Workers total={len(workers)}, idle={counts.get(\'IDLE\', 0)}"\n    }\n\ndef collect_jsonl_metrics(path, type_field, severity_field=None):\n    path = Path(path)\n    if not path.exists():\n        return {"status": "WARNING", "total": 0, "invalid": 0, "by_type": {}, "by_severity": {}, "message": f"{path.name} yok."}\n    total = 0\n    invalid = 0\n    by_type = {}\n    by_severity = {}\n    for line in safe_read(path).splitlines():\n        if not line.strip():\n            continue\n        try:\n            obj = json.loads(line)\n            total += 1\n            typ = obj.get(type_field, "UNKNOWN")\n            by_type[typ] = by_type.get(typ, 0) + 1\n            if severity_field:\n                sev = obj.get(severity_field, "UNKNOWN")\n                by_severity[sev] = by_severity.get(sev, 0) + 1\n        except Exception:\n            invalid += 1\n    status = "PASS" if invalid == 0 else "WARNING"\n    return {"status": status, "total": total, "invalid": invalid, "by_type": by_type, "by_severity": by_severity, "message": f"{path.name} total={total}, invalid={invalid}"}\n\ndef collect_latest_run_metrics():\n    patterns = {\n        "platform_core": "200_pkg_core_state_*.json",\n        "event_audit": "201_v3_event_bus_auditor_state_*.json",\n        "scheduler_engine": "202_v2_scheduler_engine_state_*.json",\n        "logger_audit": "203_logger_audit_state_*.json",\n        "docs_manager": "206*",\n    }\n    latest = {}\n    for key, pattern in patterns.items():\n        f = latest_file(STATE_DIR, pattern)\n        latest[key] = str(f) if f else None\n    return latest\n\ndef collect_all():\n    return {\n        "disk": {"free_gb": disk_free_gb(BASE_DIR), "status": "PASS" if disk_free_gb(BASE_DIR) >= 50 else "FAIL"},\n        "db": collect_db_metrics(),\n        "queue": collect_queue_metrics(),\n        "workers": collect_worker_metrics(),\n        "events": collect_jsonl_metrics(EVENT_LOG, "event_type", "severity"),\n        "logs": collect_jsonl_metrics(PLATFORM_LOG, "source", "level"),\n        "latest_runs": collect_latest_run_metrics(),\n    }\n'

EVALUATOR = '# -*- coding: utf-8 -*-\ndef evaluate(metrics):\n    score = 100\n    errors = []\n    warnings = []\n\n    if metrics["disk"]["status"] == "FAIL":\n        score -= 20\n        errors.append("Disk alanı kritik seviyede.")\n\n    if metrics["db"]["status"] == "FAIL":\n        score -= 25\n        errors.append(metrics["db"].get("message", "DB hatası."))\n\n    if metrics["queue"]["status"] == "WARNING":\n        score -= 8\n        warnings.append(metrics["queue"].get("message", "Queue warning."))\n\n    if metrics["workers"]["status"] == "WARNING":\n        score -= 8\n        warnings.append(metrics["workers"].get("message", "Worker warning."))\n\n    if metrics["events"]["invalid"] > 0:\n        score -= min(20, metrics["events"]["invalid"] * 5)\n        warnings.append("Event log içinde bozuk satır var.")\n\n    event_errors = metrics["events"].get("by_severity", {}).get("ERROR", 0) + metrics["events"].get("by_severity", {}).get("CRITICAL", 0)\n    if event_errors:\n        score -= min(20, event_errors * 3)\n        warnings.append(f"Event Bus ERROR/CRITICAL sayısı: {event_errors}")\n\n    if metrics["logs"]["invalid"] > 0:\n        score -= min(20, metrics["logs"]["invalid"] * 5)\n        warnings.append("Platform log içinde bozuk satır var.")\n\n    log_errors = metrics["logs"].get("by_severity", {}).get("ERROR", 0) + metrics["logs"].get("by_severity", {}).get("CRITICAL", 0)\n    if log_errors:\n        score -= min(20, log_errors * 3)\n        warnings.append(f"Platform Logger ERROR/CRITICAL sayısı: {log_errors}")\n\n    score = max(0, min(100, score))\n    decision = "METRICS BLOCKED" if errors else ("METRICS HEALTHY" if score >= 95 else "METRICS REVIEW")\n\n    return {"score": score, "decision": decision, "errors": errors, "warnings": warnings}\n'

MANAGER = '# -*- coding: utf-8 -*-\nimport argparse\nfrom config import BASE_DIR, STATE_DIR, REPORT_DIR, METRICS_DIR, METRICS_STORE, METRICS_HISTORY\nfrom utils import now_stamp, now_text, ensure_dirs, write_json, append_jsonl\nfrom collector import collect_all\nfrom evaluator import evaluate\n\ndef write_report(metrics, result):\n    ensure_dirs(STATE_DIR, REPORT_DIR, METRICS_DIR)\n    ts = now_stamp()\n    payload = {\n        "module": "204 Metrics & Monitoring",\n        "created_at": now_text(),\n        "metrics": metrics,\n        "result": result,\n    }\n    state = STATE_DIR / f"204_metrics_state_{ts}.json"\n    report = REPORT_DIR / f"204_metrics_raporu_{ts}.txt"\n\n    write_json(METRICS_STORE, payload)\n    write_json(state, payload)\n    append_jsonl(METRICS_HISTORY, payload)\n\n    lines = [\n        "="*80,\n        "204 METRICS & MONITORING",\n        "="*80,\n        f"Score              : {result[\'score\']} / 100",\n        f"Decision           : {result[\'decision\']}",\n        f"Errors             : {len(result[\'errors\'])}",\n        f"Warnings           : {len(result[\'warnings\'])}",\n        "",\n        "SYSTEM",\n        "-"*80,\n        f"Disk Free          : {metrics[\'disk\'].get(\'free_gb\')} GB",\n        f"DB Count           : {metrics[\'db\'].get(\'count\')}",\n        f"DB Status          : {metrics[\'db\'].get(\'status\')}",\n        "",\n        "QUEUE / WORKERS",\n        "-"*80,\n        f"Queue Total        : {metrics[\'queue\'].get(\'total\')}",\n        f"Queue Waiting      : {metrics[\'queue\'].get(\'waiting\')}",\n        f"Queue Running      : {metrics[\'queue\'].get(\'running\')}",\n        f"Queue Finished     : {metrics[\'queue\'].get(\'finished\')}",\n        f"Queue Failed       : {metrics[\'queue\'].get(\'failed\')}",\n        f"Completion Rate    : {metrics[\'queue\'].get(\'completion_rate\')}%",\n        f"Workers Total      : {metrics[\'workers\'].get(\'total\')}",\n        f"Workers Idle       : {metrics[\'workers\'].get(\'idle\')}",\n        f"Workers Running    : {metrics[\'workers\'].get(\'running\')}",\n        "",\n        "EVENTS / LOGS",\n        "-"*80,\n        f"Event Total        : {metrics[\'events\'].get(\'total\')}",\n        f"Event Invalid      : {metrics[\'events\'].get(\'invalid\')}",\n        f"Event Severity     : {metrics[\'events\'].get(\'by_severity\')}",\n        f"Log Total          : {metrics[\'logs\'].get(\'total\')}",\n        f"Log Invalid        : {metrics[\'logs\'].get(\'invalid\')}",\n        f"Log Level          : {metrics[\'logs\'].get(\'by_severity\')}",\n        "",\n        "ERRORS",\n        "-"*80,\n    ]\n    if result["errors"]:\n        for e in result["errors"]:\n            lines.append(f"- {e}")\n    else:\n        lines.append("Errors: 0")\n\n    lines += ["", "WARNINGS", "-"*80]\n    if result["warnings"]:\n        for w in result["warnings"]:\n            lines.append(f"- {w}")\n    else:\n        lines.append("Warnings: 0")\n\n    lines += [\n        "",\n        "Dosyalar:",\n        str(METRICS_STORE),\n        str(METRICS_HISTORY),\n        str(state),\n        str(report),\n    ]\n\n    report.write_text("\\n".join(lines), encoding="utf-8")\n    return {"payload": payload, "paths": {"store": str(METRICS_STORE), "history": str(METRICS_HISTORY), "state": str(state), "report": str(report)}}\n\ndef run():\n    metrics = collect_all()\n    result = evaluate(metrics)\n    return write_report(metrics, result)\n\ndef main():\n    parser = argparse.ArgumentParser()\n    parser.add_argument("--snapshot", action="store_true")\n    parser.add_argument("--status", action="store_true")\n    args = parser.parse_args()\n\n    res = run()\n    result = res["payload"]["result"]\n    metrics = res["payload"]["metrics"]\n\n    print("="*80)\n    print("204 METRICS & MONITORING TAMAMLANDI")\n    print("="*80)\n    print(f"Score           : {result[\'score\']} / 100")\n    print(f"Decision        : {result[\'decision\']}")\n    print(f"Errors          : {len(result[\'errors\'])}")\n    print(f"Warnings        : {len(result[\'warnings\'])}")\n    print(f"DB Count        : {metrics[\'db\'].get(\'count\')}")\n    print(f"Queue Total     : {metrics[\'queue\'].get(\'total\')}")\n    print(f"Queue Finished  : {metrics[\'queue\'].get(\'finished\')}")\n    print(f"Workers Total   : {metrics[\'workers\'].get(\'total\')}")\n    print(f"Event Total     : {metrics[\'events\'].get(\'total\')}")\n    print(f"Log Total       : {metrics[\'logs\'].get(\'total\')}")\n    print("")\n    print("Dosyalar:")\n    print(res["paths"]["store"])\n    print(res["paths"]["report"])\n\nif __name__ == "__main__":\n    main()\n'

BRIDGE = '# -*- coding: utf-8 -*-\nimport sys\nfrom pathlib import Path\nPACKAGE_DIR = Path(__file__).resolve().parent / "204"\nsys.path.insert(0, str(PACKAGE_DIR))\nfrom manager import main\nif __name__ == "__main__":\n    main()\n'

README = '# 204 Metrics & Monitoring\n\nNeoLegal Production Platform için merkezi metrik toplama paketidir.\n\nKomutlar:\npython ".py\\204_Metrics_Monitoring.py" --snapshot\npython ".py\\204_Metrics_Monitoring.py" --status\n'

def main():
    PY.mkdir(parents=True, exist_ok=True)
    PKG.mkdir(parents=True, exist_ok=True)

    write("README_204.md", README)
    write("config.py", CONFIG)
    write("utils.py", UTILS)
    write("collector.py", COLLECTOR)
    write("evaluator.py", EVALUATOR)
    write("manager.py", MANAGER)

    (PY / "204_Metrics_Monitoring.py").write_text(BRIDGE, encoding="utf-8")

    print("="*80)
    print("204 METRICS & MONITORING INSTALLER TAMAMLANDI")
    print("="*80)
    print("Kurulan klasör:")
    print(PKG)
    print("")
    print("Şimdi çalıştır:")
    print(r'cd /d C:\Users\MSI\Desktop\kik_proje')
    print(r'python ".py\204_Metrics_Monitoring.py" --snapshot')

if __name__ == "__main__":
    main()
